const body = $json.body || $json;
let email = '', firstName = '', fullName = '';
if (body.payload && body.payload.member && body.payload.member.email) {
  const m = body.payload.member;
  email = m.email;
  firstName = m.first_name || '';
  fullName = (m.first_name + ' ' + (m.last_name || '')).trim();
} else if (body.member && body.member.email) {
  email = body.member.email;
  fullName = body.member.full_name || body.member.name || '';
  firstName = body.member.first_name || fullName.split(' ')[0] || '';
} else if (body.data && body.data.member && body.data.member.email) {
  email = body.data.member.email;
  fullName = body.data.member.full_name || body.data.member.name || '';
  firstName = body.data.member.first_name || fullName.split(' ')[0] || '';
} else if (body.member_email) {
  email = body.member_email;
  fullName = body.member_name || '';
  firstName = body.member_first_name || fullName.split(' ')[0] || '';
} else if (body.email) {
  email = body.email;
  fullName = body.full_name || body.name || '';
  firstName = body.first_name || fullName.split(' ')[0] || '';
}
email = (email || '').toLowerCase().trim();
if (!email) throw new Error('No email found');
return [{ json: { email, firstName: firstName.trim(), fullName: fullName.trim() } }];

const subscription = $json.subscription || $json;
const member = $('Parse Member Data').first().json;
const success = !!(subscription.id || subscription.subscriber_id);
const subId = subscription.id || subscription.subscriber_id || 'unknown';
return [{ json: { success, email: member.email, sequence_name: 'Onboarding Drip Campaign', sequence_id: 'YOUR_SEQUENCE_ID', subscription_id: subId, kit_response: JSON.stringify($json).slice(0, 500) }}];
